import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.CHSDihme.js";const o="/claude-code-token-free/assets/wechat01.CU8fJc0V.png",l="/claude-code-token-free/assets/wechat03.C5bSWaa_.png",d="/claude-code-token-free/assets/wechat02.YMMPMkkK.jpg",g=JSON.parse('{"title":"微信接入","description":"","frontmatter":{},"headers":[],"relativePath":"im/wechat.md","filePath":"im/wechat.md","lastUpdated":1780319135000}'),c={name:"im/wechat.md"};function n(p,e,h,r,k,u){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="微信接入" tabindex="-1">微信接入 <a class="header-anchor" href="#微信接入" aria-label="Permalink to &quot;微信接入&quot;">​</a></h1><blockquote><p>微信 Adapter 的接入教程。桌面端扫码绑定机器人账号后，再用配对码授权具体微信用户。</p></blockquote><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>微信方案适合个人私聊远程使用。当前实现支持文本聊天、语音转文字内容、图片和文件附件、项目选择、状态查看、停止生成和权限审批。</p><p>当前只按私聊用户维度授权和保存会话，不面向微信群聊设计。</p><p>实现入口：<code>adapters/wechat/index.ts</code></p><h2 id="1-扫码绑定微信机器人账号" tabindex="-1">1. 扫码绑定微信机器人账号 <a class="header-anchor" href="#1-扫码绑定微信机器人账号" aria-label="Permalink to &quot;1. 扫码绑定微信机器人账号&quot;">​</a></h2><p>打开桌面端 <code>设置 -&gt; IM 接入 -&gt; 微信</code>。</p><p>在微信标签页里：</p><ol><li>点击「扫码绑定」。</li><li>使用微信扫描页面里的二维码。</li><li>在微信里确认登录。</li><li>等待页面显示绑定成功。</li><li>点击保存，或确认当前配置已经写入本地。</li></ol><p><img src="'+o+'" alt="微信未绑定时的扫码入口"></p><p>扫码成功后，桌面端会把微信网关返回的 <code>accountId</code>、<code>botToken</code>、<code>baseUrl</code> 和 <code>userId</code> 写入 <code>~/.claude/adapters.json</code> 的 <code>wechat</code> 配置。发布版桌面端会重启 adapter sidecar，让新凭据立即生效。</p><p>绑定成功后，微信标签页会显示「微信已绑定」，并提供「重新扫码」和「解除微信绑定」：</p><p><img src="'+l+'" alt="微信绑定成功状态"></p><p>注意：扫码绑定的是机器人账号凭据，不等于把所有微信用户都授权了。用户访问仍然走 <code>allowedUsers + pairedUsers</code> 授权模型。</p><h2 id="2-授权具体微信用户" tabindex="-1">2. 授权具体微信用户 <a class="header-anchor" href="#2-授权具体微信用户" aria-label="Permalink to &quot;2. 授权具体微信用户&quot;">​</a></h2><p>推荐走配对码：</p><ol><li>在 <code>设置 -&gt; IM 接入</code> 顶部的「配对管理」里点击「生成配对码」。</li><li>把 6 位配对码发给微信里的机器人。</li><li>看到配对成功提示后，就可以直接发送自然语言消息。</li></ol><p><img src="'+d+`" alt="微信里发送配对码并开始对话"></p><p>配对码有效期 60 分钟，一次性使用。重新生成配对码后，旧码会失效。</p><p>也可以把已知微信用户 ID 手动写进微信标签页的 <code>Allowed Users</code>。这种方式适合固定账号白名单，但一般没有配对码直观。</p><h2 id="3-选择项目并开始对话" tabindex="-1">3. 选择项目并开始对话 <a class="header-anchor" href="#3-选择项目并开始对话" aria-label="Permalink to &quot;3. 选择项目并开始对话&quot;">​</a></h2><p>如果已经配置默认项目，发送任意消息会直接在该目录下创建或复用 Claude Code session。</p><p>如果没有配置默认项目，微信 adapter 会返回最近项目列表。回复编号、项目名或绝对路径后，会新建会话并绑定到当前微信用户。</p><p>后续消息会复用 <code>~/.claude/adapter-sessions.json</code> 里的 chat 到 session 映射。发送 <code>/new</code> 可以重新选择项目并开启新会话。</p><h2 id="支持的命令" tabindex="-1">支持的命令 <a class="header-anchor" href="#支持的命令" aria-label="Permalink to &quot;支持的命令&quot;">​</a></h2><p>微信没有可配置菜单，命令入口就是聊天框。配对成功后，bot 会提示发送 <code>/help</code>；后续随时发 <code>/help</code> 或 <code>帮助</code> 都能看到当前支持的命令。</p><ul><li><code>/help</code> 或 <code>帮助</code> — 显示可用命令</li><li><code>/status</code> 或 <code>状态</code> — 查看当前会话的项目、分支、模型、运行状态和任务摘要</li><li><code>/projects</code> 或 <code>项目列表</code> — 重新显示最近项目列表</li><li><code>/new</code> 或 <code>新会话</code> — 清空当前 chat 绑定的 session，并重新选择项目</li><li><code>/new &lt;编号、项目名或绝对路径&gt;</code> — 直接在指定项目下新建会话</li><li><code>/clear</code> 或 <code>清空</code> — 清空当前会话上下文，保留项目绑定</li><li><code>/stop</code> 或 <code>停止</code> — 向当前 session 发送 <code>stop_generation</code></li></ul><h2 id="权限审批" tabindex="-1">权限审批 <a class="header-anchor" href="#权限审批" aria-label="Permalink to &quot;权限审批&quot;">​</a></h2><p>当 Claude 请求敏感权限时，微信 adapter 会发送一条文本审批消息，里面包含 request id。</p><p>在微信里回复：</p><ul><li><code>/allow &lt;requestId&gt;</code> — 允许一次权限请求</li><li><code>/always &lt;requestId&gt;</code> — 永久允许同类权限请求</li><li><code>/deny &lt;requestId&gt;</code> — 拒绝一次权限请求</li></ul><p>审批结果会通过 WebSocket 桥接回桌面端 session。</p><h2 id="返回消息的表现" tabindex="-1">返回消息的表现 <a class="header-anchor" href="#返回消息的表现" aria-label="Permalink to &quot;返回消息的表现&quot;">​</a></h2><ul><li>使用 <code>getupdates</code> 长轮询接收微信消息。</li><li>流式回复约每 1.2 秒或满 200 字批量发送一次（模型生成完成后会立即刷出剩余内容）。</li><li>文本回复按 3500 字左右分片发送。</li><li>thinking 和工具执行期间会尽量发送微信 typing 状态。</li><li>图片会以内联图片形式进入模型输入；非图片文件会以本地临时文件路径传给会话。</li><li>附件会走公共大小限制检查，超限时 adapter 会在微信里返回提示。</li></ul><h2 id="解绑" tabindex="-1">解绑 <a class="header-anchor" href="#解绑" aria-label="Permalink to &quot;解绑&quot;">​</a></h2><p>有两种解绑：</p><ul><li>解绑微信机器人账号：在微信标签页点击「解绑微信账号」，会清空 <code>wechat.accountId</code>、<code>wechat.botToken</code>、<code>wechat.userId</code>、<code>allowedUsers</code> 和 <code>pairedUsers</code>。</li><li>解绑某个用户：在「已配对用户」列表里点击对应微信用户右侧的「解绑」，只移除该用户的 <code>pairedUsers</code> 记录。</li></ul><p>解绑机器人账号后需要重新扫码绑定。解绑用户后，该用户需要重新发送新的配对码才能继续使用。</p><h2 id="本地开发启动" tabindex="-1">本地开发启动 <a class="header-anchor" href="#本地开发启动" aria-label="Permalink to &quot;本地开发启动&quot;">​</a></h2><p>发布版桌面端会自动启动 adapter sidecar。只有本地开发或单独调试时才需要手动运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> adapters</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wechat</span></span></code></pre></div><p>可选环境变量：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> WECHAT_ACCOUNT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> WECHAT_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> WECHAT_BASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://ilinkai.weixin.qq.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> WECHAT_USER_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADAPTER_SERVER_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ws://127.0.0.1:3456&quot;</span></span></code></pre></div><p>正常桌面端使用不需要手动设置这些环境变量，扫码绑定会写入本地配置。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="扫码成功后发消息仍提示未授权" tabindex="-1">扫码成功后发消息仍提示未授权 <a class="header-anchor" href="#扫码成功后发消息仍提示未授权" aria-label="Permalink to &quot;扫码成功后发消息仍提示未授权&quot;">​</a></h3><p>这是正常授权流程的一部分。扫码绑定只写入机器人账号凭据；具体微信用户还需要发送配对码，或被加入 <code>Allowed Users</code>。</p><h3 id="页面显示二维码过期" tabindex="-1">页面显示二维码过期 <a class="header-anchor" href="#页面显示二维码过期" aria-label="Permalink to &quot;页面显示二维码过期&quot;">​</a></h3><p>重新点击「扫码绑定」生成新二维码。微信二维码登录状态只在短时间内有效。</p><h3 id="adapter-启动时报缺少微信账号" tabindex="-1">adapter 启动时报缺少微信账号 <a class="header-anchor" href="#adapter-启动时报缺少微信账号" aria-label="Permalink to &quot;adapter 启动时报缺少微信账号&quot;">​</a></h3><p>说明 <code>WECHAT_ACCOUNT_ID / WECHAT_BOT_TOKEN</code> 和 <code>~/.claude/adapters.json</code> 里的 <code>wechat.accountId / wechat.botToken</code> 都没有生效。先在桌面端微信标签页完成扫码绑定。</p><h3 id="收不到回复" tabindex="-1">收不到回复 <a class="header-anchor" href="#收不到回复" aria-label="Permalink to &quot;收不到回复&quot;">​</a></h3><p>优先检查：</p><ul><li>桌面端是否正在运行。</li><li>微信标签页是否显示已绑定。</li><li>当前用户是否已经配对或在 <code>Allowed Users</code> 中。</li><li><code>~/.claude/adapters.json</code> 是否能正常写入。</li><li>本地开发时 <code>ADAPTER_SERVER_URL</code> 是否指向正在运行的 Desktop server WebSocket 地址。</li></ul><h3 id="会话没恢复" tabindex="-1">会话没恢复 <a class="header-anchor" href="#会话没恢复" aria-label="Permalink to &quot;会话没恢复&quot;">​</a></h3><p>检查 <code>~/.claude/adapter-sessions.json</code> 是否能正常写入，以及 Desktop server 里的 session 是否仍存在。</p><h3 id="im-使用的模型不对" tabindex="-1">IM 使用的模型不对 <a class="header-anchor" href="#im-使用的模型不对" aria-label="Permalink to &quot;IM 使用的模型不对&quot;">​</a></h3><p>桌面聊天页按 session 选模型；微信 IM 新建 session 时优先用空会话页草稿（<code>imRuntimeDefault</code>），否则用全局激活 Provider。改模型后请发 <code>/new</code>，详见 <a href="./../im/#5-im-使用的模型--provider">IM 总览 — 模型说明</a>。</p><h2 id="源码入口" tabindex="-1">源码入口 <a class="header-anchor" href="#源码入口" aria-label="Permalink to &quot;源码入口&quot;">​</a></h2><ul><li><code>adapters/wechat/index.ts</code></li><li><code>adapters/wechat/protocol.ts</code></li><li><code>adapters/wechat/media.ts</code></li><li><code>adapters/common/pairing.ts</code></li><li><code>adapters/common/session-store.ts</code></li><li><code>adapters/common/ws-bridge.ts</code></li><li><code>adapters/common/http-client.ts</code></li></ul>`,61)])])}const m=a(c,[["render",n]]);export{g as __pageData,m as default};
